<article class="product-card"><a class="product-visual" href="<?=url('/produk/'.$x['slug'])?>"><?php if($x['image_path']):?><img src="<?=url('/media/'.$x['image_path'])?>" alt="<?=e($x['name'])?>" loading="lazy"><?php else:?><span><?=e(substr($x['name'],0,1))?></span><?php endif?><?php if((int)$x['stock_qty']<=0):?><b class="sold-out">Habis</b><?php elseif($x['pricing']['discount']>0):?><b>Promo</b><?php endif?></a><div><small><?=e($x['category_name']??'Pilihan')?></small><h3><a href="<?=url('/produk/'.$x['slug'])?>"><?=e($x['name'])?></a></h3><p><?php if($x['pricing']['discount']):?><del><?=money($x['pricing']['base'])?></del><?php endif?><strong><?=money($x['pricing']['final'])?></strong></p></div></article>
